vector<ll> pre[N], suf[N]; // 一组 k 个人，前 i 组的答案的总和
Math::PreInv<N, mod> inv;
void solve(int CASE)
{
	int n, q; cin >> n >> q;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	sort(all1(a), greater<>());
	var presum = vector<ll>(n + 2);
	var sufsum = vector<ll>(n + 2);
	fa(i, 1, n)presum[i] = presum[i - 1] + a[i];
	fb(i, n, 1)sufsum[i] = sufsum[i + 1] + a[i];

	fa(k, 1, n) { // 一组 k 个
		pre[k].pb(0);
		// 调和级数复杂度
		for (int i = k; i <= n; i += k) {
			ll zi = Math::fastPow(presum[i] - presum[i - k], 2, mod);
			ll mu = inv[k] * inv[k] % mod;
			ll now = zi * mu % mod; // 美丽度
			pre[k].pb((pre[k].back() + now) % mod);
		}
	}

	fa(k, 1, n) { // 一组 k 个
		suf[k].pb(0);
		// 调和级数复杂度
		for (int i = n - k + 1; i >= 1; i -= k) {
			ll zi = Math::fastPow(sufsum[i] - sufsum[i + k], 2, mod);
			ll mu = inv[k] * inv[k] % mod;
			ll now = zi * mu % mod; // 美丽度
			suf[k].pb((suf[k].back() + now) % mod);
		}
	}

	while (q--) {
		int l, r; cin >> l >> r;

		if (l == r) {
			if (n % l != 0)cout << -1 << endl;
			else cout << pre[l][n / l] << endl;
			continue;
		}

		// 分组：
		//	1. 若干个大小为 l 的组，拿前面最大的宝石
		//	2. (最多 1 个)大小为 mid 的组，l < mid < r
		//  3. 若干个大小为 r 的组，拿后面最小的宝石

		int k = n / l;             // l 人一组，最大组数

		// 把 l 组全改成 r 都装不满 n
		if (1ll * k * r < n) {
			cout << -1 << endl;
			continue;
		}

		int left = n - k * l;      // 剩下的没组的人数
		int add = r - l;           // 每组最多在加 add 个人
		int num_r = left / add;    // 装满 r 个人的组有 num_r 个
		left = left - num_r * add; // 剩下没装入 l,r 组的人数
		int num_l = k - num_r;     // 装满 l 个人的组有 num_l 个
		int mid = l + left;        // 中间组大小
		if (mid > l)num_l--;       // 存在中间组

		ll ans = 0;
		ans = (ans + pre[l][num_l]) % mod;
		ans = (ans + suf[r][num_r]) % mod;
		if (mid > l) {
			int L = l * num_l + 1;
			int R = n - r * num_r;
			ll zi = Math::fastPow(presum[R] - presum[L - 1], 2, mod);
			ll mu = inv[mid] * inv[mid] % mod;
			ll now = zi * mu % mod; // 美丽度
			ans = (ans + now) % mod;
		}
		cout << ans << endl;
	}
	return;
}
